8	// LifecycleTransitionOptions contains the explicit facts required to validate
9	// status changes whose meaning would otherwise be implicit in caller policy.
10	type LifecycleTransitionOptions struct {
11		OperatorRequired      bool
12		ExternalBlockerReason string
13		ManualClose           bool
14		ManualReopen          bool
15		Reason                string
16		Actor                 string
17		Source                string
18	}
19	
20	// LifecycleDependencyState is the small dependency shape the pure lifecycle
21	// core needs. Store callers can adapt richer dependency records into this type.
22	type LifecycleDependencyState struct {
23		Status string
24	}
25	
26	// LifecycleQueueFacts contains all queue-classification inputs as caller-owned
27	// facts. It deliberately avoids store access, filesystem access, configuration,
28	// process execution, git access, and clock reads.
29	type LifecycleQueueFacts struct {
30		Status                  string
31		Dependencies            []LifecycleDependencyState
32		ClaimFresh              bool
33		RetryCooldownActive     bool
34		ExecutionEligible       bool
35		ExecutionEligibleKnown  bool
36		SupersededBy            string
37		EpicContainer           bool
38		ExternalBlockerReason   string
39		LegacyLabels            []string
40		LegacyMigrationWarnings []string
41	}
42	
43	// LifecycleQueueBucket is the derived queue state used by dispatch, review,
44	// and operator-facing views. It is not persisted as bead.Status.
45	type LifecycleQueueBucket string
46	
47	const (
48		LifecycleBucketReady               LifecycleQueueBucket = "ready"
49		LifecycleBucketWaitingDependencies LifecycleQueueBucket = "waiting_dependencies"
50		LifecycleBucketProposed            LifecycleQueueBucket = "proposed"
51		LifecycleBucketClaimed             LifecycleQueueBucket = "claimed"
52		LifecycleBucketBlockedExternal     LifecycleQueueBucket = "blocked_external"
53		LifecycleBucketClosedTerminal      LifecycleQueueBucket = "closed_terminal"
54		LifecycleBucketCancelledTerminal   LifecycleQueueBucket = "cancelled_terminal"
55		LifecycleBucketRetryCooldown       LifecycleQueueBucket = "retry_cooldown"
56		LifecycleBucketNotEligible         LifecycleQueueBucket = "not_eligible"
57		LifecycleBucketSuperseded          LifecycleQueueBucket = "superseded"
58		LifecycleBucketEpicContainer       LifecycleQueueBucket = "epic_container"
59		LifecycleBucketInvalid             LifecycleQueueBucket = "invalid"
60	)
61	
62	// LifecycleIssueCode identifies validation findings from pure lifecycle
63	// evaluation. Issues explain bad facts; they do not mutate status or labels.
64	type LifecycleIssueCode string
65	
66	const (
67		LifecycleIssueInvalidStatus                LifecycleIssueCode = "invalid_status"
68		LifecycleIssueBlockedMissingExternalReason LifecycleIssueCode = "blocked_missing_external_reason"
69		LifecycleIssueTransitionRequiresOperator   LifecycleIssueCode = "transition_requires_operator"
70		LifecycleIssueTransitionRequiresExternal   LifecycleIssueCode = "transition_requires_external_blocker"
71		LifecycleIssueTransitionFromTerminal       LifecycleIssueCode = "transition_from_terminal"
72		LifecycleIssueTransitionUnsupported        LifecycleIssueCode = "transition_unsupported"
73		LifecycleIssueLegacyLabelLifecycleMetadata LifecycleIssueCode = "legacy_label_lifecycle_metadata"
74		LifecycleIssueLegacyMigrationCompatibility LifecycleIssueCode = "legacy_migration_compatibility"
75	)
76	
77	// LifecycleIssue is a deterministic, caller-displayable finding.
78	type LifecycleIssue struct {
79		Code   LifecycleIssueCode
80		Detail string
81	}
82	
83	// LifecycleQueueDecision is the pure result of evaluating LifecycleQueueFacts.
84	type LifecycleQueueDecision struct {
85		Bucket                LifecycleQueueBucket
86		WorkerEligible        bool
87		OperatorAttention     bool
88		DependenciesSatisfied bool
89		SatisfiesDependents   bool
90		Issues                []LifecycleIssue
91		Warnings              []string
92		ExternalBlockerReason string
93	}
94	
95	// ValidateLifecycleTransition returns nil when from -> to is a valid persisted
96	// status transition under the supplied explicit facts.
97	func ValidateLifecycleTransition(from, to string, opts LifecycleTransitionOptions) error {
98		if err := validateLifecycleStatus(from); err != nil {
99			return err
100		}
101		if err := validateLifecycleStatus(to); err != nil {
102			return err
103		}
104		if from == to {
105			return nil
106		}
107		if to == StatusClosed && opts.ManualClose {
108			switch from {
109			case StatusOpen, StatusInProgress, StatusBlocked, StatusProposed:
110				return nil
111			}
112		}
113		if from == StatusClosed && to == StatusOpen && opts.ManualReopen {
114			return nil
115		}
116		if from == StatusClosed || from == StatusCancelled {
117			return lifecycleTransitionError(LifecycleIssueTransitionFromTerminal, from, to)
118		}
119		if to == StatusProposed && !opts.OperatorRequired {
120			return lifecycleTransitionError(LifecycleIssueTransitionRequiresOperator, from, to)
121		}
122		if to == StatusBlocked && strings.TrimSpace(opts.ExternalBlockerReason) == "" {
123			return lifecycleTransitionError(LifecycleIssueTransitionRequiresExternal, from, to)
124		}
125		if lifecycleTransitionAllowed(from, to) {
126			return nil
127		}
128		return lifecycleTransitionError(LifecycleIssueTransitionUnsupported, from, to)
129	}
130	
131	// CanLifecycleTransition is a convenience predicate around
132	// ValidateLifecycleTransition.
133	func CanLifecycleTransition(from, to string, opts LifecycleTransitionOptions) bool {
134		return ValidateLifecycleTransition(from, to, opts) == nil
135	}
136	
137	// LifecycleStatusSatisfiesDependency reports whether a persisted status
138	// satisfies dependent beads. Only closed satisfies dependents.
139	func LifecycleStatusSatisfiesDependency(status string) bool {
140		return status == StatusClosed
141	}
142	
143	// LifecycleDependenciesSatisfied reports whether every dependency is closed.
144	func LifecycleDependenciesSatisfied(deps []LifecycleDependencyState) bool {
145		for _, dep := range deps {
146			if !LifecycleStatusSatisfiesDependency(dep.Status) {
147				return false
148			}
149		}
150		return true
151	}
152	
153	// EvaluateLifecycleQueue derives queue state from caller-provided facts. Legacy
154	// lifecycle labels are reported as warnings only; they never choose the bucket.
155	func EvaluateLifecycleQueue(f LifecycleQueueFacts) LifecycleQueueDecision {
156		decision := LifecycleQueueDecision{
157			DependenciesSatisfied: LifecycleDependenciesSatisfied(f.Dependencies),
158			SatisfiesDependents:   LifecycleStatusSatisfiesDependency(f.Status),
159		}
160		decision.Warnings = append(decision.Warnings, lifecycleLegacyLabelWarnings(f.LegacyLabels)...)
161		for _, warning := range f.LegacyMigrationWarnings {
162			trimmed := strings.TrimSpace(warning)
163			if trimmed == "" {
164				continue
165			}
166			decision.Issues = append(decision.Issues, LifecycleIssue{
167				Code:   LifecycleIssueLegacyMigrationCompatibility,
168				Detail: trimmed,
169			})
170			decision.Warnings = append(decision.Warnings, trimmed)
171		}
172	
173		if err := validateLifecycleStatus(f.Status); err != nil {
174			decision.Bucket = LifecycleBucketInvalid
175			decision.Issues = append(decision.Issues, LifecycleIssue{
176				Code:   LifecycleIssueInvalidStatus,
177				Detail: err.Error(),
178			})
179			return decision
180		}
181	
182		switch f.Status {
183		case StatusClosed:
184			decision.Bucket = LifecycleBucketClosedTerminal
185		case StatusCancelled:
186			decision.Bucket = LifecycleBucketCancelledTerminal
187		case StatusProposed:
188			decision.Bucket = LifecycleBucketProposed
189			decision.OperatorAttention = true
190		case StatusInProgress:
191			if f.ClaimFresh {
192				decision.Bucket = LifecycleBucketClaimed
193				return decision
194			}
195			decision = evaluateOpenLifecycleQueue(f, decision)
196		case StatusBlocked:
197			decision.Bucket = LifecycleBucketBlockedExternal
198			decision.ExternalBlockerReason = strings.TrimSpace(f.ExternalBlockerReason)
199			if decision.ExternalBlockerReason == "" {
200				decision.Issues = append(decision.Issues, LifecycleIssue{
201					Code:   LifecycleIssueBlockedMissingExternalReason,
202					Detail: "blocked status requires an explicit external blocker reason",
203				})
204			}
205		case StatusOpen:
206			decision = evaluateOpenLifecycleQueue(f, decision)
207		}
208		return decision
209	}
210	
211	func evaluateOpenLifecycleQueue(f LifecycleQueueFacts, decision LifecycleQueueDecision) LifecycleQueueDecision {
212		if !decision.DependenciesSatisfied {
213			decision.Bucket = LifecycleBucketWaitingDependencies
214			return decision
215		}
216		if strings.TrimSpace(f.SupersededBy) != "" {
217			decision.Bucket = LifecycleBucketSuperseded
218			return decision
219		}
220		if f.EpicContainer {
221			decision.Bucket = LifecycleBucketEpicContainer
222			return decision
223		}
224		if f.RetryCooldownActive {
225			decision.Bucket = LifecycleBucketRetryCooldown
226			return decision
227		}
228		if f.ExecutionEligibleKnown && !f.ExecutionEligible {
229			decision.Bucket = LifecycleBucketNotEligible
230			return decision
231		}
232		decision.Bucket = LifecycleBucketReady
233		decision.WorkerEligible = true
234		return decision
235	}
236	
237	func validateLifecycleStatus(status string) error {
238		if IsCanonicalStatus(status) {
239			return nil
240		}
241		return fmt.Errorf("%s: %q", LifecycleIssueInvalidStatus, status)
242	}
243	
244	func lifecycleTransitionAllowed(from, to string) bool {
245		switch from {
246		case StatusProposed:
247			return to == StatusOpen || to == StatusCancelled
248		case StatusOpen:
249			return to == StatusInProgress || to == StatusBlocked || to == StatusProposed || to == StatusCancelled
250		case StatusInProgress:
251			return to == StatusOpen || to == StatusClosed || to == StatusBlocked || to == StatusProposed
252		case StatusBlocked:
253			return to == StatusOpen || to == StatusProposed || to == StatusCancelled
254		default:
255			return false
256		}
257	}
258	
259	func lifecycleTransitionError(code LifecycleIssueCode, from, to string) error {
260		return fmt.Errorf("%s: %s -> %s", code, from, to)
261	}
262	
263	func lifecycleLegacyLabelWarnings(labels []string) []string {
264		var warnings []string
265		for _, label := range labels {
266			switch label {
267			case LabelNeedsHuman, LabelNeedsInvestigation:
268				warnings = append(warnings, fmt.Sprintf("%s: label %q is explanatory metadata, not lifecycle state", LifecycleIssueLegacyLabelLifecycleMetadata, label))
269			default:
270				if hasNoChangesTriageLabelValue(label) {
271					warnings = append(warnings, fmt.Sprintf("%s: label %q is explanatory metadata, not lifecycle state", LifecycleIssueLegacyLabelLifecycleMetadata, label))
272				}
273			}
274		}
275		return warnings
276	}
277	
278	func hasNoChangesTriageLabelValue(label string) bool {
279		for _, triageLabel := range noChangesTriageLabels {
280			if label == triageLabel {
281				return true
282			}
283		}
284		return false
285	}
