546	func (s *Store) updateBead(id string, allowStatusChange bool, mutate func(*Bead) error) error {
547		return s.WithLock(func() error {
548			beads, _, err := s.readAllLatestRaw()
549			if err != nil {
550				return err
551			}
552			found := false
553			for i := range beads {
554				if beads[i].ID == id {
555					beforeStatus := beads[i].Status
556					if mutate != nil {
557						if err := mutate(&beads[i]); err != nil {
558							return err
559						}
560					}
561					if !allowStatusChange && beads[i].Status != beforeStatus {
562						return fmt.Errorf("bead: lifecycle status change %s -> %s requires Store.TransitionLifecycle", beforeStatus, beads[i].Status)
563					}
564					beads[i].UpdatedAt = time.Now().UTC()
565					// Core validation after mutation
566					if err := s.validateBead(&beads[i]); err != nil {
567						return err
568					}
569					// Run update hook
570					if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
571						return err
572					}
573					found = true
574					break
575				}
576			}
577			if !found {
578				return fmt.Errorf("bead: not found: %s", id)
579			}
580			return s.WriteAll(beads)
581		})
582	}
