584	// TransitionLifecycle validates and persists one bead lifecycle status
585	// transition. Callers may provide a mutator for metadata that must land
586	// atomically with the status write.
587	func (s *Store) TransitionLifecycle(id string, status string, opts LifecycleTransitionOptions, mutate func(*Bead) error) error {
588		return s.updateBead(id, true, func(b *Bead) error {
589			if err := transitionLifecycleInPlace(b, status, opts); err != nil {
590				return err
591			}
592			if mutate != nil {
593				return mutate(b)
594			}
595			return nil
596		})
597	}
