604	// UpdateWithLifecycleStatus atomically applies non-status field mutations and
605	// a validated lifecycle status transition.
606	func (s *Store) UpdateWithLifecycleStatus(id string, status string, opts LifecycleTransitionOptions, mutate func(*Bead) error) error {
607		return s.updateBead(id, true, func(b *Bead) error {
608			beforeStatus := b.Status
609			if mutate != nil {
610				if err := mutate(b); err != nil {
611					return err
612				}
613			}
614			if b.Status != beforeStatus {
615				return fmt.Errorf("bead: UpdateWithLifecycleStatus mutator changed lifecycle status directly")
616			}
617			return transitionLifecycleInPlace(b, status, opts)
618		})
619	}
