621	func transitionLifecycleInPlace(b *Bead, status string, opts LifecycleTransitionOptions) error {
622		from := b.Status
623		if err := ValidateLifecycleTransition(from, status, opts); err != nil {
624			return fmt.Errorf("bead: lifecycle transition %s -> %s rejected: %w", from, status, err)
625		}
626		b.Status = status
627		applyLifecycleTransitionMetadata(b, status, opts)
628		return nil
629	}
