743	// Heartbeat refreshes the external claim liveness lease on a claimed bead.
744	// Returns an error if the bead is no longer in_progress (e.g., reclaimed by
745	// another worker), allowing the caller to stop its heartbeat loop.
746	//
747	// Deprecated: use TouchClaimHeartbeat.
748	func (s *Store) Heartbeat(id string) error {
749		if err := s.WithLock(func() error {
750			beads, _, err := s.readAllLatestRaw()
751			if err != nil {
752				return err
753			}
754			for _, b := range beads {
755				if b.ID != id {
756					continue
757				}
758				if b.Status != StatusInProgress {
759					return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, b.Status)
760				}
761				return s.TouchClaimHeartbeat(id)
762			}
763			return fmt.Errorf("bead: not found: %s", id)
764		}); err != nil {
765			return err
766		}
767		return nil
768	}
