770	// claimLeaseIsStale returns true if the external claim lease is absent or
771	// older than HeartbeatTTL. When no lease file exists, it falls back to the
772	// legacy execute-loop-heartbeat-at tracker field for compatibility.
773	func claimLeaseIsStale(s *Store, extra map[string]any, id string) bool {
774		if s != nil {
775			if fresh, found, err := s.ClaimHeartbeatFresh(id); err == nil {
776				if found {
777					return !fresh
778				}
779			} else {
780				return heartbeatIsStale(extra)
781			}
782		}
783		return heartbeatIsStale(extra)
784	}
785	
786	// heartbeatIsStale returns true if the given bead's Extra map has no
787	// execute-loop-heartbeat-at or one older than HeartbeatTTL.
788	func heartbeatIsStale(extra map[string]any) bool {
789		if extra == nil {
790			return true
791		}
792		raw, ok := extra["execute-loop-heartbeat-at"]
793		if !ok {
794			return true
795		}
796		s, ok := raw.(string)
797		if !ok || s == "" {
798			return true
799		}
800		t, err := time.Parse(time.RFC3339Nano, s)
801		if err != nil {
802			// Fall back to RFC3339 for compatibility with legacy entries written
803			// before sub-second resolution. RFC3339Nano is the current canonical
804			// format used by both ClaimWithOptions and Heartbeat write sites.
805			t, err = time.Parse(time.RFC3339, s)
806			if err != nil {
807				return true
808			}
809		}
810		return time.Since(t) > HeartbeatTTL
811	}
