822					return err
823				}
824			}
825			b.Owner = ""
826			if b.Extra != nil {
827				delete(b.Extra, "claimed-at")
828				delete(b.Extra, "claimed-pid")
829				delete(b.Extra, "claimed-machine")
830				delete(b.Extra, "claimed-session")
831				delete(b.Extra, "claimed-worktree")
832				delete(b.Extra, "execute-loop-heartbeat-at")
833			}
834			return nil
835		}); err != nil {
836			return err
