856	// IncrNoChangesCount increments the execute-loop no-changes counter for a bead
857	// and returns the new count. Used by the execute-bead worker to detect when a
858	// bead should be auto-closed after repeated no-change attempts.
859	func (s *Store) IncrNoChangesCount(id string) (int, error) {
860		var newCount int
861		err := s.Update(id, func(b *Bead) {
862			if b.Extra == nil {
863				b.Extra = make(map[string]any)
864			}
865			var count int
866			if v, ok := b.Extra["execute-loop-no-changes-count"]; ok {
867				switch n := v.(type) {
868				case int:
869					count = n
870				case float64:
871					count = int(n)
872				case int64:
873					count = int(n)
874				}
875			}
876			count++
877			b.Extra["execute-loop-no-changes-count"] = count
878			newCount = count
879		})
880		return newCount, err
881	}
