883	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
884	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
885	// DDx-authored beads always round-trip through `bd import`. Empirically
886	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
887	const MaxFieldBytes = 65535
888	
889	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
890	// need to preserve the full payload should persist it to a sidecar artifact
891	// and store a path reference in the field; this function is the defense-in-
892	// depth cap for code paths that don't. Returns the input unchanged when it
893	// fits; otherwise returns head+tail truncation with a byte-count marker.
894	func capFieldBytes(s string) string {
895		if len(s) <= MaxFieldBytes {
896			return s
897		}
898		// Reserve a marker that always fits; keep head heavy (2/3) so
899		// human-readable context is preserved for the common short-rationale case.
900		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
901		budget := MaxFieldBytes - len(marker)
902		if budget <= 0 {
903			return s[:MaxFieldBytes]
904		}
905		head := (budget * 2) / 3
906		tail := budget - head
907		return s[:head] + marker + s[len(s)-tail:]
908	}
909	
910	// Cancel-marker keys on Bead.Extra. ADR-022 §Cancel SLA: an operator-initiated
911	// cancel writes cancel-requested:true; the worker that honors the cancel writes
912	// cancel-honored:true alongside it.
913	const (
914		ExtraCancelRequested = "cancel-requested"
915		ExtraCancelHonored   = "cancel-honored"
916	)
917	
918	// RequestCancel writes Extra[cancel-requested]=true on the bead. Idempotent:
919	// if cancel-honored is already set the call is a silent no-op (the prior cancel
920	// was already consumed). Returns true when the marker is now set on the bead
921	// (either by this call or a prior one).
922	func (s *Store) RequestCancel(id string) (bool, error) {
923		var set bool
924		err := s.Update(id, func(b *Bead) {
925			if b.Extra == nil {
926				b.Extra = make(map[string]any)
927			}
928			if isExtraTrue(b.Extra[ExtraCancelHonored]) {
929				set = isExtraTrue(b.Extra[ExtraCancelRequested])
930				return
931			}
932			b.Extra[ExtraCancelRequested] = true
933			set = true
934		})
935		return set, err
936	}
937	
938	// IsCancelRequested reports whether the bead carries an unconsumed cancel
939	// marker (cancel-requested:true and cancel-honored not yet set).
940	func (s *Store) IsCancelRequested(id string) (bool, error) {
941		b, err := s.Get(id)
942		if err != nil {
943			return false, err
944		}
945		if b == nil || b.Extra == nil {
946			return false, nil
947		}
948		if isExtraTrue(b.Extra[ExtraCancelHonored]) {
949			return false, nil
950		}
951		return isExtraTrue(b.Extra[ExtraCancelRequested]), nil
952	}
953	
954	// MarkCancelHonored sets Extra[cancel-honored]=true. Called by the worker once
955	// it has aborted at the next safe point in response to a cancel request.
956	func (s *Store) MarkCancelHonored(id string) error {
957		return s.Update(id, func(b *Bead) {
958			if b.Extra == nil {
959				b.Extra = make(map[string]any)
960			}
961			b.Extra[ExtraCancelHonored] = true
962		})
963	}
964	
965	func isExtraTrue(v any) bool {
966		switch x := v.(type) {
967		case bool:
968			return x
969		case string:
970			return x == "true"
971		}
972		return false
973	}
