1042	// EventsByKind returns all events for a bead filtered by kind, in insertion order.
1043	func (s *Store) EventsByKind(id, kind string) ([]BeadEvent, error) {
1044		all, err := s.Events(id)
1045		if err != nil {
1046			return nil, err
1047		}
1048		out := make([]BeadEvent, 0, len(all))
1049		for _, e := range all {
1050			if e.Kind == kind {
1051				out = append(out, e)
1052			}
1053		}
1054		return out, nil
1055	}
