1129	// externalizeEvents moves a bead's inline events into its sidecar attachment
1130	// under a fresh lock. Safe to call repeatedly — no-op when there are no
1131	// inline events (already externalized, or none recorded).
1132	func (s *Store) externalizeEvents(id string) error {
1133		if s.axonGraphQLActive() {
1134			return nil
1135		}
