1154	// ErrClosureGateRejected indicates a close was refused because the bead does
1155	// not carry the evidence required for an automated closure: a terminal
1156	// verdict event (review APPROVE with non-empty rationale, or an explicit
1157	// review-skipped / manual-close marker) AND an execution-evidence marker
1158	// (closing_commit_sha, session_id, or an execute-bead success event in the
1159	// events history).
1160	//
1161	// Automated execute-loop paths (execute-bead + reviewer) always go through
1162	// CloseWithEvidence. The plain Store.Close remains as the manual
1163	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
1164	// acceptance §1).
1165	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
1166	
1167	// ClosureGate inspects a bead and returns nil iff the close is safe. It
1168	// rejects only the specific shapes that caused the 2026-04-18/20
1169	// review-malfunction incidents:
1170	//
1171	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
1172	//     closing_commit_sha. Rejected by the execution-evidence check —
1173	//     closing_commit_sha must be non-empty OR at least one event must exist.
1174	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
1175	//     body is empty. Rejected — APPROVE with no rationale is exactly the
1176	//     parse-mis-extract shape the reviewer bug produced.
1177	//
1178	// Beads without a review step (--no-review, no Reviewer configured, already-
1179	// satisfied paths) pass the gate as long as they carry execution evidence.
1180	// This keeps the surface small: the gate catches known-bad shapes, not every
1181	// conceivable edge case. Additional invariants belong in future dedicated
1182	// beads so the rejection reason stays auditable.
1183	func ClosureGate(b *Bead) error {
1184		if b == nil {
1185			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
1186		}
1187		hasClosingCommit := false
1188		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
1189			hasClosingCommit = true
1190		}
1191		events := decodeBeadEvents(b.Extra["events"])
1192		// Externalized events still count as evidence for the gate. We only need
1193		// to know whether *some* event history exists, not iterate it; the
1194		// gate's APPROVE-with-empty-rationale check below relies on inline events
1195		// (the verdict is recorded before externalization).
1196		hasAttachedEvents := hasEventsAttachment(b)
1197		// Reject the axon-c5cc071a shape: no events AND no closing commit.
1198		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
1199			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
1200		}
1201		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
1202		for _, e := range events {
1203			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
1204				if strings.TrimSpace(e.Body) == "" {
1205					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
1206				}
1207			}
1208		}
1209		return nil
1210	}
