1264	func appendClosureRejectNote(b *Bead, err error) {
1265		stamp := time.Now().UTC().Format(time.RFC3339)
1266		note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
1267		if b.Notes == "" {
1268			b.Notes = note
1269			return
1270		}
1271		b.Notes = b.Notes + "\n" + note
