1382	// List returns beads matching optional filters.
1383	// where is an optional map of key=value predicates that match against
1384	// known struct fields and Extra (unknown/workflow-specific) fields.
1385	func (s *Store) List(status, label string, where map[string]string) ([]Bead, error) {
1386		beads, err := s.ReadAll()
1387		if err != nil {
1388			return nil, err
1389		}
1390		var result []Bead
1391		for _, b := range beads {
1392			if status != "" && b.Status != status {
1393				continue
1394			}
1395			if label != "" && !containsString(b.Labels, label) {
1396				continue
1397			}
1398			if !matchesWhere(b, where) {
1399				continue
1400			}
1401			result = append(result, b)
