1610	// HumanReviewBlockerPressure describes an open human-review blocker and the
1611	// number of active downstream beads that transitively depend on it.
1612	type HumanReviewBlockerPressure struct {
1613		ID                     string
1614		Title                  string
1615		Priority               int
1616		DownstreamBlockedCount int
1617	}
1618	
1619	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1620		out := ReadyExecutionBreakdown{}
1621		beads, err := s.ReadAll()
1622		if err != nil {
1623			return out, err
1624		}
1625		now := time.Now().UTC()
1626		var soonestRetry time.Time
1627		for _, entry := range s.classifyLifecycleQueue(beads, now) {
1628			switch entry.Decision.Bucket {
1629			case LifecycleBucketReady:
1630				out.ExecutionReady = append(out.ExecutionReady, entry.ID)
1631			case LifecycleBucketWaitingDependencies:
1632				out.DependencyWaiting = append(out.DependencyWaiting, entry.ID)
1633			case LifecycleBucketRetryCooldown:
1634				out.RetryCooldown = append(out.RetryCooldown, entry.ID)
1635				if !entry.RetryAfter.IsZero() && (soonestRetry.IsZero() || entry.RetryAfter.Before(soonestRetry)) {
1636					soonestRetry = entry.RetryAfter
1637				}
1638			case LifecycleBucketEpicContainer:
1639				if entry.EpicClosureCandidate {
1640					out.EpicClosureCandidates = append(out.EpicClosureCandidates, entry.ID)
1641				} else {
1642					out.Epics = append(out.Epics, entry.ID)
1643				}
1644			case LifecycleBucketNotEligible:
1645				out.NotEligible = append(out.NotEligible, entry.ID)
1646			case LifecycleBucketSuperseded:
1647				out.Superseded = append(out.Superseded, entry.ID)
1648			case LifecycleBucketBlockedExternal:
1649				out.ExternalBlocked = append(out.ExternalBlocked, entry.ID)
1650			case LifecycleBucketProposed:
1651				out.ProposedOperatorAttention = append(out.ProposedOperatorAttention, entry.ID)
1652			}
1653		}
1654		if !soonestRetry.IsZero() {
1655			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1656		}
1657		out.HumanReviewBlockers, out.HumanReviewBlockedTotal = humanReviewBlockerPressure(beads)
1658		return out, nil
1659	}
