1831	// BlockedAll returns open beads that are currently not runnable, classified
1832	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1833	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1834	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1835	// that is both dep-blocked and cooldown-parked is reported as dependency-
1836	// blocked, because deps are the stronger blocker.
1837	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1838		beads, err := s.ReadAll()
1839		if err != nil {
1840			return nil, err
1841		}
1842	
1843		now := time.Now().UTC()
1844		var entries []BlockedBead
1845		for _, entry := range s.classifyLifecycleQueue(beads, now) {
1846			switch entry.Decision.Bucket {
1847			case LifecycleBucketWaitingDependencies:
1848				entries = append(entries, BlockedBead{
1849					Bead: entry.Bead,
1850					Blocker: Blocker{
1851						Kind:           BlockerKindDependency,
1852						UnclosedDepIDs: entry.UnclosedDepIDs,
1853					},
1854				})
1855			case LifecycleBucketBlockedExternal:
1856				reason := entry.Decision.ExternalBlockerReason
1857				if reason == "" && len(entry.Decision.Issues) > 0 {
1858					reason = entry.Decision.Issues[0].Detail
1859				}
1860				entries = append(entries, BlockedBead{
1861					Bead: entry.Bead,
1862					Blocker: Blocker{
1863						Kind:   BlockerKindBlockedStatus,
1864						Reason: reason,
1865					},
1866				})
1867			case LifecycleBucketProposed:
1868				entries = append(entries, BlockedBead{
1869					Bead: entry.Bead,
1870					Blocker: Blocker{
1871						Kind:   BlockerKindOperatorAttention,
1872						Reason: "status=proposed requires operator attention",
1873					},
1874				})
1875			case LifecycleBucketEpicContainer:
1876				entries = append(entries, BlockedBead{
1877					Bead: entry.Bead,
1878					Blocker: Blocker{
1879						Kind:   BlockerKindEpicOnly,
1880						Reason: "ordinary ddx work skips epic/container beads",
1881					},
1882				})
1883			case LifecycleBucketNotEligible:
1884				entries = append(entries, BlockedBead{
1885					Bead: entry.Bead,
1886					Blocker: Blocker{
1887						Kind:   BlockerKindNotEligible,
1888						Reason: entry.ExecutionSkipReason,
1889					},
1890				})
1891			case LifecycleBucketSuperseded:
1892				entries = append(entries, BlockedBead{
1893					Bead: entry.Bead,
1894					Blocker: Blocker{
1895						Kind:   BlockerKindSuperseded,
1896						Reason: entry.SupersededBy,
1897					},
1898				})
1899			case LifecycleBucketRetryCooldown:
1900				entries = append(entries, BlockedBead{
1901					Bead: entry.Bead,
1902					Blocker: Blocker{
1903						Kind:           BlockerKindRetryCooldown,
1904						NextEligibleAt: entry.RetryAfter.UTC().Format(time.RFC3339),
1905						LastStatus:     entry.LastStatus,
1906						LastDetail:     entry.LastDetail,
1907					},
1908				})
1909			}
1910		}
1911	
1912		sort.SliceStable(entries, func(i, j int) bool {
1913			if entries[i].Priority != entries[j].Priority {
1914				return entries[i].Priority < entries[j].Priority
1915			}
1916			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1917				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1918			}
1919			return entries[i].ID < entries[j].ID
1920		})
1921		return entries, nil
1922	}
