1924	func isOrdinaryEpicContainer(b Bead, childCount int) bool {
1925		issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
1926		title := strings.ToLower(strings.TrimSpace(b.Title))
1927		return issueType == "epic" || strings.HasPrefix(title, "epic:") || (childCount > 0 && strings.HasPrefix(title, "epic "))
1928	}
1929	
1930	func isEpicClosureCandidate(b Bead, childCount, openChildCount int) bool {
1931		if childCount == 0 {
1932			return false
1933		}
1934		return isOrdinaryEpicContainer(b, childCount) && openChildCount == 0
1935	}
