1937	func sortBeadsForQueue(beads []Bead) {
1938		sort.SliceStable(beads, func(i, j int) bool {
1939			if beads[i].Priority != beads[j].Priority {
1940				return beads[i].Priority < beads[j].Priority
1941			}
1942			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
1943			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
1944			if iok != jok {
1945				return iok
1946			}
1947			if iok && jok && ir != jr {
1948				return ir < jr
1949			}
1950			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1951				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1952			}
1953			return beads[i].ID < beads[j].ID
1954		})
1955	}
1956	
1957	func parseQueueRank(raw any) (int, bool) {
1958		switch v := raw.(type) {
1959		case int:
1960			return v, true
1961		case int8:
1962			return int(v), true
1963		case int16:
1964			return int(v), true
1965		case int32:
1966			return int(v), true
1967		case int64:
1968			return int(v), true
1969		case uint:
1970			return int(v), true
1971		case uint8:
1972			return int(v), true
1973		case uint16:
1974			return int(v), true
1975		case uint32:
1976			return int(v), true
1977		case uint64:
1978			return int(v), true
1979		case float32:
1980			return int(v), v == float32(int(v))
1981		case float64:
1982			return int(v), v == float64(int(v))
1983		case json.Number:
1984			if n, err := v.Int64(); err == nil {
1985				return int(n), true
1986			}
1987			if f, err := v.Float64(); err == nil {
1988				return int(f), f == float64(int(f))
1989			}
1990		case string:
1991			if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
1992				return n, true
1993			}
1994		}
1995		return 0, false
1996	}
