1998	// Status returns aggregate counts.
1999	func (s *Store) Status() (*StatusCounts, error) {
2000		beads, err := s.ReadAll()
2001		if err != nil {
2002			return nil, err
2003		}
2004		ready, err := s.Ready()
2005		if err != nil {
2006			return nil, err
2007		}
2008		workerReady, err := s.ReadyExecution()
2009		if err != nil {
2010			return nil, err
2011		}
2012		needsHuman, err := s.ProposedOperatorAttention()
2013		if err != nil {
2014			return nil, err
2015		}
2016	
2017		// Pull in archive partner so totals survive `bead migrate` — the archive
2018		// only carries closed beads, so Ready/Blocked aren't affected.
2019		seen := make(map[string]bool, len(beads))
2020		all := make([]Bead, 0, len(beads))
2021		for _, b := range beads {
2022			if seen[b.ID] {
2023				continue
2024			}
2025			seen[b.ID] = true
2026			all = append(all, b)
2027		}
2028		if s.Collection == DefaultCollection {
2029			archive := s.archivePartner()
2030			if archived, aerr := archive.ReadAll(); aerr == nil {
2031				for _, b := range archived {
2032					if seen[b.ID] {
2033						continue
2034					}
2035					seen[b.ID] = true
2036					all = append(all, b)
2037				}
2038			}
2039		}
2040	
2041		counts := &StatusCounts{
2042			Total:             len(all),
2043			Ready:             len(ready),
2044			WorkerReady:       len(workerReady),
2045			NeedsHuman:        len(needsHuman),
2046			OperatorAttention: len(needsHuman),
2047		}
2048		for _, b := range all {
2049			switch b.Status {
2050			case StatusOpen:
2051				counts.Open++
2052			case StatusInProgress:
2053				counts.InProgress++
2054			case StatusClosed:
2055				counts.Closed++
2056			case StatusBlocked:
2057				counts.Blocked++
2058			case StatusProposed:
2059				counts.Proposed++
2060			case StatusCancelled:
2061				counts.Cancelled++
2062			}
2063		}
2064		for _, entry := range s.classifyLifecycleQueue(beads, time.Now().UTC()) {
2065			switch entry.Decision.Bucket {
2066			case LifecycleBucketWaitingDependencies:
2067				counts.DependencyWaiting++
2068			case LifecycleBucketBlockedExternal:
2069				counts.ExternalBlocked++
2070			}
2071		}
2072		return counts, nil
2073	}
